    var onPushMessage: (([String: Any]) -> Void)?
    var onPurchaseMessage: (([String: Any]) -> Void)?

    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        guard let body = message.body as? [String: Any] else { return }

        switch message.name {
        case MessageName.camera.rawValue:
            onCameraMessage?(body)
        case MessageName.pushNotifications.rawValue:
            onPushMessage?(body)
        case MessageName.inAppPurchase.rawValue:
            onPurchaseMessage?(body)
        default:
            break
        }
    }
}

