}

final class InAppPurchaseManager {
    enum PurchaseError: LocalizedError {
        case productNotFound
        case verificationFailed
        case userCancelled
        case unsupportedOS

        var errorDescription: String? {
            switch self {
            case .productNotFound: return "Product not found"
            case .verificationFailed: return "Transaction verification failed"
            case .userCancelled: return "User cancelled purchase"
            case .unsupportedOS: return "In-app purchases require iOS 15 or later"
            }
        }
    }

    @available(iOS 15.0, *)
    private var cachedProducts: [Product] = []

    func fetchProducts(productIDs: [String], completion: @escaping (Result<[StoreProductPayload], Error>) -> Void) {
        guard #available(iOS 15.0, *) else {
            completion(.failure(PurchaseError.unsupportedOS))
            return
        }

        Task {
            do {
                let products = try await Product.products(for: productIDs)
                self.cachedProducts = products
                let payload = products.map {
                    StoreProductPayload(
                        id: $0.id,
                        displayName: $0.displayName,
                        description: $0.description,
                        displayPrice: $0.displayPrice
                    )
                }
                completion(.success(payload))
            } catch {
                completion(.failure(error))
            }
        }
    }

    func purchase(productID: String, completion: @escaping (Result<String, Error>) -> Void) {
        guard #available(iOS 15.0, *) else {
            completion(.failure(PurchaseError.unsupportedOS))
            return
        }

        Task {
            do {
                let product: Product
                if let cached = cachedProducts.first(where: { $0.id == productID }) {
                    product = cached
                } else {
                    let products = try await Product.products(for: [productID])
                    guard let first = products.first else {
                        completion(.failure(PurchaseError.productNotFound))
                        return
                    }
                    product = first
                }

                let result = try await product.purchase()
                switch result {
                case .success(let verification):
                    let transaction = try checkVerified(verification)
                    await transaction.finish()
                    completion(.success(String(transaction.id)))
                case .userCancelled:
                    completion(.failure(PurchaseError.userCancelled))
                case .pending:
                    completion(.failure(NSError(domain: "IAP", code: 1, userInfo: [NSLocalizedDescriptionKey: "Purchase pending"])))
                @unknown default:
                    completion(.failure(NSError(domain: "IAP", code: 2, userInfo: [NSLocalizedDescriptionKey: "Unknown purchase result"])))
                }
            } catch {
                completion(.failure(error))
            }
        }
    }

    @available(iOS 15.0, *)
    private func checkVerified<T>(_ result: VerificationResult<T>) throws -> T {
        switch result {
        case .unverified:
            throw PurchaseError.verificationFailed
        case .verified(let safe):
            return safe
        }
    }
}

struct StoreProductPayload {
    let id: String
    let displayName: String
    let description: String
    let displayPrice: String
}